package com.rnllama;

import androidx.annotation.NonNull;
import com.facebook.react.bridge.Promise;
import com.facebook.react.bridge.ReactApplicationContext;
import com.facebook.react.bridge.ReactContextBaseJavaModule;
import com.facebook.react.bridge.ReactMethod;
import com.facebook.react.bridge.ReadableMap;
import com.facebook.react.bridge.WritableMap;
import com.facebook.react.bridge.ReactContext;
import com.facebook.react.bridge.Arguments;
import com.facebook.react.modules.core.DeviceEventManagerModule;
import com.facebook.react.turbomodule.core.CallInvokerHolderImpl;

import java.util.Map;
import java.util.HashMap;

public class RNLlamaModule extends ReactContextBaseJavaModule {
  public static final String NAME = "RNLlama";

  public RNLlamaModule(ReactApplicationContext reactContext) {
    super(reactContext);
  }

  @Override
  @NonNull
  public String getName() {
    return NAME;
  }

  @Override
  public Map<String, Object> getConstants() {
      return new HashMap<>();
  }

  @ReactMethod
  public void install(Promise promise) {
    try {
      boolean loaded = RNLlama.loadNative(getReactApplicationContext());
      if (!loaded) {
        promise.resolve(false);
        return;
      }
      long jsContextPointer = getReactApplicationContext().getJavaScriptContextHolder().get();
      CallInvokerHolderImpl holder = (CallInvokerHolderImpl) getReactApplicationContext().getCatalystInstance().getJSCallInvokerHolder();
      if (jsContextPointer == 0 || holder == null) {
        promise.resolve(false);
        return;
      }
      installJSIBindings(jsContextPointer, holder);
      promise.resolve(true);
    } catch (Exception e) {
      promise.resolve(false);
    }
  }

  private native void installJSIBindings(long jsContextPointer, CallInvokerHolderImpl callInvokerHolder);
  private native void cleanupJSIBindings();

  @ReactMethod
  public void initContext(ReadableMap params, Promise promise) {
    promise.resolve(null);
  }

  @ReactMethod
  public void releaseContext(double contextId, Promise promise) {
    promise.resolve(null);
  }

  @ReactMethod
  public void completion(double contextId, ReadableMap params, Promise promise) {
     promise.resolve(null);
  }
  
  @ReactMethod
  public void stopCompletion(double contextId, Promise promise) {
    promise.resolve(null);
  }

  @ReactMethod
  public void getFormattedChat(double contextId, ReadableMap params, Promise promise) {
    promise.resolve("");
  }

  @ReactMethod
  public void loadSession(double contextId, String path, Promise promise) {
     promise.resolve(null);
  }

  @ReactMethod
  public void saveSession(double contextId, String path, Promise promise) {
     promise.resolve("");
  }
}
